import java.util.*;

public class Solution {

    static class TreeNode {
        int val;
        TreeNode left, right;
        TreeNode(int val) { this.val = val; }
    }

    private int diameter = 0;

    public int diameterOfBinaryTree(TreeNode root) {
        if (root == null) return 0;
        height(root);
        return diameter;
    }

    // Returns height (in edges) of subtree; updates diameter along the way.
    private int height(TreeNode node) {
        if (node == null) return 0;
        int leftH = height(node.left);
        int rightH = height(node.right);
        // longest path through this node = leftH + rightH (edges)
        diameter = Math.max(diameter, leftH + rightH);
        return 1 + Math.max(leftH, rightH);
    }

    public static void main(String[] args) {
        Solution s = new Solution();

        // Test 1: [1,2,3,4,5] -> expected 3
        TreeNode root = s.new TreeNode(1);
        root.left = s.new TreeNode(2);
        root.right = s.new TreeNode(3);
        root.left.left = s.new TreeNode(4);
        root.left.right = s.new TreeNode(5);
        check("Test1 [1,2,3,4,5]", s.diameterOfBinaryTree(root), 3);

        // Test 2: single node -> 0
        Solution s2 = new Solution();
        check("Test2 single node", s2.diameterOfBinaryTree(s2.new TreeNode(1)), 0);

        // Test 3: two nodes -> 1
        Solution s3 = new Solution();
        TreeNode r3 = s3.new TreeNode(1);
        r3.left = s3.new TreeNode(2);
        check("Test3 two nodes", s3.diameterOfBinaryTree(r3), 1);

        // Test 4: left-skewed chain of 5 nodes -> 4 edges
        Solution s4 = new Solution();
        TreeNode r4 = s4.new TreeNode(1);
        TreeNode cur = r4;
        for (int i = 2; i <= 5; i++) { cur.left = s4.new TreeNode(i); cur = cur.left; }
        check("Test4 skewed chain", s4.diameterOfBinaryTree(r4), 4);

        // Test 5: path not through root.
        // root has left subtree that is deep on both sides; right is null.
        //        1
        //       /
        //      2
        //     / \
        //    3   4
        //   /     \
        //  5       6
        // longest path 5->3->2->4->6 = 4 edges, not through root
        Solution s5 = new Solution();
        TreeNode r5 = s5.new TreeNode(1);
        r5.left = s5.new TreeNode(2);
        r5.left.left = s5.new TreeNode(3);
        r5.left.right = s5.new TreeNode(4);
        r5.left.left.left = s5.new TreeNode(5);
        r5.left.right.right = s5.new TreeNode(6);
        check("Test5 path not through root", s5.diameterOfBinaryTree(r5), 4);

        // Test 6: null root -> 0
        Solution s6 = new Solution();
        check("Test6 null root", s6.diameterOfBinaryTree(null), 0);

        System.out.println("ALL DONE");
    }

    private static void check(String name, int got, int expected) {
        String status = (got == expected) ? "PASS" : "FAIL";
        System.out.println(status + " - " + name + ": got=" + got + " expected=" + expected);
    }
}

